        modelBuilder.Entity<KioskRenewalPayment>(entity =>
        {
            entity
                .HasNoKey()
                .ToTable("Kiosk_Renewal_Payment");

            entity.Property(e => e.AcademyName)
                .HasMaxLength(100)
                .IsUnicode(false);
            entity.Property(e => e.BankReferenceNo)
                .HasMaxLength(50)
                .IsUnicode(false);
            entity.Property(e => e.CessAmount)
                .HasComputedColumnSql("((([OriginalAmount]-[Discount])/(114.5))*(0.5))", false)
                .HasColumnType("numeric(19, 7)");
            entity.Property(e => e.CreatedBy)
                .HasMaxLength(50)
                .IsUnicode(false);
            entity.Property(e => e.CreatedOn).HasColumnType("datetime");
            entity.Property(e => e.FinalAmount).HasComputedColumnSql("([OriginalAmount]-[Discount])", false);
            entity.Property(e => e.FinanceApprovalOn).HasColumnType("datetime");
            entity.Property(e => e.KioskCode)
                .HasMaxLength(10)
                .IsUnicode(false);
            entity.Property(e => e.PaymentId).ValueGeneratedOnAdd();
            entity.Property(e => e.ProductId)
                .HasMaxLength(5)
                .IsUnicode(false)
                .HasComputedColumnSql("([dbo].[CustomerNumber]([PaymentId]))", false)
                .IsFixedLength();
            entity.Property(e => e.RefundTxnDate).HasColumnType("datetime");
            entity.Property(e => e.RefundTxnId).HasColumnName("RefundTxnID");
            entity.Property(e => e.Remarks)
                .HasMaxLength(100)
                .IsUnicode(false);
            entity.Property(e => e.RenewalCode)
                .HasMaxLength(20)
                .IsUnicode(false);
            entity.Property(e => e.Rfees).HasColumnName("RFees");
            entity.Property(e => e.RserviceTax).HasColumnName("RServiceTax");
            entity.Property(e => e.ServiceTaxAmount)
                .HasComputedColumnSql("(case when [PaymentId]>(50) then (([OriginalAmount]-[Discount])/(114.5))*(14.5) else (([OriginalAmount]-[Discount])/(114))*(14) end)", false)
                .HasColumnType("numeric(21, 7)");
            entity.Property(e => e.TransactionId)
                .HasMaxLength(50)
                .IsUnicode(false);
            entity.Property(e => e.Year)
                .HasMaxLength(20)
                .IsUnicode(false);
        });

